rule.example:

// Bad practice - hardcoded credentials
String apiKey = "sk-1234567890abcdef";
String password = "hardcoded-password";

// Good practice - use vault or environment
String apiKey = vaultService.getOpenAICredentials().apiKey;
String password = System.getenv("DB_PASSWORD");


// Bad practice - direct environment access
String token = System.getenv("GITHUB_TOKEN");

// Good practice - use vault service
String token = vaultService.getGitHubCredentials().token;


// Bad practice - no error handling
String secret = vault.readSecret("path/to/secret");

// Good practice - with error handling
try {
    String secret = vault.readSecret("path/to/secret");
} catch (VaultException e) {
    logger.error("Failed to read secret", e);
    throw new CredentialException("Vault access failed", e);
}


// Bad practice - logging sensitive data
logger.info("Using token: " + token);
logger.debug("Secret key: " + secretKey);

// Good practice - masked logging
logger.info("Using token: " + maskCredential(token));
logger.debug("Authentication successful");


// Bad practice - resource not managed
VaultService vault = new VaultService(config);
String secret = vault.readSecret("path");

// Good practice - with try-with-resources
try (VaultService vault = new VaultService(config)) {
    String secret = vault.readSecret("path");
}
